# Load employee photos and train model
def load_and_train_model():
    known_encodings = []
    known_names = []
    for root, dirs, files in os.walk('employee_photos'):
        for file in files:
            if file.endswith(('jpg', 'jpeg', 'png')):
                path = os.path.join(root, file)
                image = face_recognition.load_image_file(path)
                encodings = face_recognition.face_encodings(image)
                if encodings:
                    known_encodings.append(encodings[0])
                    known_names.append(os.path.basename(root))
    label_encoder = LabelEncoder()
    labels = label_encoder.fit_transform(known_names)
    model = SVC(kernel='linear', probability=True)
    model.fit(known_encodings, labels)
    return model, label_encoder

model, label_encoder = load_and_train_model()

# Secure API endpoint
@app.route('/recognize', methods=['POST'])
def recognize():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    filename = secure_filename(file.filename)
    if not filename:
        return jsonify({'error': 'Invalid filename'}), 400
    file_path = os.path.join('/tmp', filename)
    file.save(file_path)

    image = face_recognition.load_image_file(file_path)
    encodings = face_recognition.face_encodings(image)
    if not encodings:
        return jsonify({'error': 'No face found'}), 400

    face_encoding = encodings[0]
    probabilities = model.predict_proba([face_encoding])[0]
    class_indices = np.argsort(probabilities)[::-1]
    response = {
        'probabilities': {
            label_encoder.inverse_transform([i])[0]: float(probabilities[i])
            for i in class_indices
        }
    }
    os.remove(file_path)
    return jsonify(response)

